Transaction — check out one client, always release in `finally`:

```js
async function transfer(from, to, amt) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('UPDATE acct SET bal = bal - $1 WHERE id = $2', [amt, from]);
    await client.query('UPDATE acct SET bal = bal + $1 WHERE id = $2', [amt, to]);
    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();   // MUST — else leak client, pool starve
  }
}
```

